package inequivalent;

import org.junit.jupiter.api.Test;

import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair73Method2Test {

    private final ClonePair73 subject = new ClonePair73();

    @Test
    void method2SplitsTermsSeparatedByAsciiSpaces() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("alpha", "beta", "gamma"), subject.method2("alpha beta gamma"));
    }

    @Test
    void method2PreservesQuotedTermContainingSpaces() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("\"alpha beta\"", "gamma"), subject.method2("\"alpha beta\" gamma"));
    }

    @Test
    void method2TreatsFullWidthSpacesAsSeparators() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("alpha", "beta"), subject.method2("alpha　beta"));
    }

    @Test
    void method2AcceptsUnclosedQuotedTermUntilEndOfInput() {
        // Generated by Codex (gpt-5.4).
        assertEquals(List.of("\"alpha beta"), subject.method2("\"alpha beta"));
    }

    @Test
    void method2ThrowsNullPointerExceptionForNullQuery() {
        // Generated by Codex (gpt-5.4).
        assertThrows(NullPointerException.class, () -> subject.method2(null));
    }
}
